/**
 * Back-pressure for AI coding agents.
 *
 * `cai verify` runs the cheap checks an agent should pass before declaring
 * "done": typecheck, build, drift. Each step is auto-detected from the
 * project's manifest — no config file needed.
 *
 * Exit codes follow Claude Code's hook contract:
 *   0 — everything passed (or skipped because not applicable)
 *   2 — at least one check failed; Claude Code re-engages the agent
 *
 * Output is human-friendly by default, machine-readable with --json so the
 * Stop hook can pipe it back into the agent's context.
 *
 * Design principles:
 *   - Fast: skip slow tests (run a separate `cai verify --full` for those)
 *   - Honest: never silently skip a step the project actually has
 *   - Bounded: each step has a timeout so a runaway script can't hang the hook
 */
import { existsSync } from "node:fs";
import { spawnSync } from "node:child_process";
import { join } from "node:path";
import chalk from "chalk";
import type { CaiConfig, ProjectModel } from "./types.js";
import { scanProjectModel } from "./scanner/manifest.js";
import { runDriftCheck } from "./drift/index.js";

export interface VerifyStep {
  name: string;
  command: string;
  status: "passed" | "failed" | "skipped";
  durationMs: number;
  output?: string;
  reason?: string;
}

export interface VerifyResult {
  passed: boolean;
  steps: VerifyStep[];
  totalDurationMs: number;
}

interface VerifyOptions {
  /** Skip drift check (useful when running drift separately) */
  skipDrift?: boolean;
  /** Per-step timeout in ms */
  timeoutMs?: number;
}

const DEFAULT_TIMEOUT_MS = 120_000;

/** Run all auto-detected verification steps. */
export async function runVerify(config: CaiConfig, opts: VerifyOptions = {}): Promise<VerifyResult> {
  const start = Date.now();
  const steps: VerifyStep[] = [];
  const project = scanProjectModel(config.projectRoot);
  const timeout = opts.timeoutMs ?? DEFAULT_TIMEOUT_MS;

  // 1. Typecheck — TypeScript projects only
  const typecheckStep = await runTypecheck(config.projectRoot, project, timeout);
  if (typecheckStep) steps.push(typecheckStep);

  // Stop early on hard failure — no point continuing if types are broken
  if (steps.some((s) => s.status === "failed")) {
    return finalize(steps, start);
  }

  // 2. Build — only if a build script exists
  const buildStep = await runBuild(config.projectRoot, project, timeout);
  if (buildStep) steps.push(buildStep);

  if (steps.some((s) => s.status === "failed")) {
    return finalize(steps, start);
  }

  // 3. Drift check — always (unless skipped)
  if (!opts.skipDrift) {
    const driftStep = await runDriftStep(config);
    steps.push(driftStep);
  }

  return finalize(steps, start);
}

function finalize(steps: VerifyStep[], startMs: number): VerifyResult {
  return {
    passed: steps.every((s) => s.status !== "failed"),
    steps,
    totalDurationMs: Date.now() - startMs,
  };
}

async function runTypecheck(projectRoot: string, project: ProjectModel, timeoutMs: number): Promise<VerifyStep | null> {
  // Only Node.js projects with a tsconfig.json get a typecheck step
  if (project.rootManifest?.type !== "package.json") return null;
  if (!existsSync(join(projectRoot, "tsconfig.json"))) return null;

  const scripts = project.rootManifest.scripts ?? {};
  // Prefer an explicit typecheck script if it exists
  if (scripts.typecheck) {
    return runShell("typecheck", "npm run typecheck", projectRoot, timeoutMs);
  }
  if (scripts["type-check"]) {
    return runShell("typecheck", "npm run type-check", projectRoot, timeoutMs);
  }
  // Fall back to direct tsc invocation
  return runShell("typecheck", "npx tsc --noEmit", projectRoot, timeoutMs);
}

async function runBuild(projectRoot: string, project: ProjectModel, timeoutMs: number): Promise<VerifyStep | null> {
  if (project.rootManifest?.type !== "package.json") return null;
  const scripts = project.rootManifest.scripts ?? {};
  if (!scripts.build) return null;
  return runShell("build", "npm run build", projectRoot, timeoutMs);
}

async function runDriftStep(config: CaiConfig): Promise<VerifyStep> {
  const stepStart = Date.now();
  try {
    // Use --fast equivalent: skip the staleness checker (slow due to git ops)
    const report = await runDriftCheck(config, { skip: ["staleness"] });
    const errors = report.issues.filter((i) => i.severity === "error").length;
    const status: VerifyStep["status"] = errors > 0 ? "failed" : "passed";
    const summary = errors > 0
      ? `${errors} error${errors !== 1 ? "s" : ""} (score ${report.score}/100)`
      : `clean (score ${report.score}/100)`;
    return {
      name: "drift",
      command: "cai check --skip staleness",
      status,
      durationMs: Date.now() - stepStart,
      output: summary,
    };
  } catch (err) {
    return {
      name: "drift",
      command: "cai check --skip staleness",
      status: "failed",
      durationMs: Date.now() - stepStart,
      output: (err as Error).message,
    };
  }
}

function runShell(name: string, command: string, cwd: string, timeoutMs: number): VerifyStep {
  const stepStart = Date.now();
  // Split the command into argv. Keep it simple — these commands are all
  // generated by us, no shell metachars to worry about.
  const parts = command.split(/\s+/);
  const result = spawnSync(parts[0], parts.slice(1), {
    cwd,
    encoding: "utf8",
    timeout: timeoutMs,
    stdio: ["ignore", "pipe", "pipe"],
    maxBuffer: 4 * 1024 * 1024,
  });

  if (result.error) {
    const code = (result.error as NodeJS.ErrnoException).code;
    if (code === "ENOENT") {
      return {
        name,
        command,
        status: "skipped",
        durationMs: Date.now() - stepStart,
        reason: `${parts[0]} not found in PATH`,
      };
    }
    return {
      name,
      command,
      status: "failed",
      durationMs: Date.now() - stepStart,
      output: result.error.message,
    };
  }

  // Combine stdout and stderr for the agent's context — both can carry useful info
  const combined = ((result.stdout ?? "") + "\n" + (result.stderr ?? "")).trim();

  if (result.status === 0) {
    return {
      name,
      command,
      status: "passed",
      durationMs: Date.now() - stepStart,
    };
  }

  return {
    name,
    command,
    status: "failed",
    durationMs: Date.now() - stepStart,
    output: truncate(combined, 4000),
  };
}

function truncate(text: string, maxChars: number): string {
  if (text.length <= maxChars) return text;
  return text.slice(0, maxChars) + `\n… (truncated, ${text.length - maxChars} more chars)`;
}

/** Pretty-print the verify result for humans. */
export function printVerifyResult(result: VerifyResult): void {
  console.log();
  console.log(chalk.bold("  cai verify"));
  console.log();

  for (const step of result.steps) {
    const icon = step.status === "passed" ? chalk.green("✔")
      : step.status === "failed" ? chalk.red("✖")
      : chalk.dim("○");
    const duration = chalk.dim(`(${(step.durationMs / 1000).toFixed(1)}s)`);

    console.log(`  ${icon} ${chalk.bold(step.name.padEnd(10))}  ${chalk.dim(step.command)}  ${duration}`);

    if (step.status === "skipped" && step.reason) {
      console.log(`            ${chalk.dim(step.reason)}`);
    }
    if (step.status === "passed" && step.output) {
      console.log(`            ${chalk.dim(step.output)}`);
    }
    if (step.status === "failed" && step.output) {
      const lines = step.output.split("\n").slice(0, 12);
      for (const line of lines) {
        console.log(`            ${chalk.dim(line)}`);
      }
      if (step.output.split("\n").length > 12) {
        console.log(`            ${chalk.dim("…")}`);
      }
    }
  }

  console.log();
  if (result.passed) {
    console.log(`  ${chalk.green("✓ all checks passed")}  ${chalk.dim(`(${(result.totalDurationMs / 1000).toFixed(1)}s total)`)}`);
  } else {
    const failed = result.steps.filter((s) => s.status === "failed").map((s) => s.name).join(", ");
    console.log(`  ${chalk.red("✖ failed:")} ${chalk.bold(failed)}  ${chalk.dim(`(${(result.totalDurationMs / 1000).toFixed(1)}s total)`)}`);
  }
  console.log();
}
